import { execSync, StdioOptions } from "child_process";
import path from "path";

export class PdfGenerator {
  static generatePdf(latexFilePath: string, output: string,stdioOption:StdioOptions='ignore'): string {
    const dir = path.dirname(output);
    const outputFile = output;

    try {
      execSync(`pdflatex -output-directory="${dir}" ${latexFilePath}`, {
        stdio: stdioOption,
      });
      
      return outputFile;
    } catch (error) {
      throw new Error("PDF generation failed:" + JSON.stringify(error));
    }
  }
}
